const codeReusability = "The signature of a method defines how a function or method should be called and what parameters and return values are expected. This clear contract makes your code flexible and reusable. For example:\r\n\r\n```go\r\npackage main\r\n\r\nimport \"fmt\"\r\n\r\ntype Greeter interface {\r\n    Greet() string\r\n}\r\n\r\n// Person struct implements the Greeter interface\r\ntype Person struct {\r\n    Name string\r\n}\r\n\r\nfunc (p Person) Greet() string {\r\n    return \"Hello, \" + p.Name + \"!\"\r\n}\r\n\r\n// SayHello accepts any type that satisfies the interface value Greeter.\r\nfunc SayHello(g Greeter) {\r\n    fmt.Println(g.Greet())\r\n}\r\n\r\nfunc main() {\r\n    p := Person{Name: \"John\"}\r\n    SayHello(p)\r\n}\r\n``` ";

