const inputFromCommandLine = "In order to take user input from the command line, you can use the `readline` module. It provides an interface for reading data from a Readable stream (such as `process.stdin`) one line at a time.\r\n\r\n```js\r\nimport readline from 'node:readline';\r\nimport { stdin as input, stdout as output } from 'node:process';\r\n\r\nconst rl = readline.createInterface({ input, output });\r\n\r\nrl.question('What do you think of Node.js? ', (answer) => {\r\n  console.log(`Thank you for your valuable feedback: ${answer}`);\r\n  rl.close();\r\n});\r\n\r\nrl.on('close', () => {\r\n  console.log('\\nBYE BYE !!!');\r\n  process.exit(0);\r\n});\r\n```\r\n";

