const middlewarePattern = "Middleware is a function that has access to the request object, response object, and the next middleware function in the application's request-response cycle. It's a core pattern in Express.js and similar frameworks for handling HTTP requests in a modular way.\r\n\r\n## Basic Middleware Structure\r\n\r\n```js\r\n// Middleware function signature\r\nfunction middleware(req, res, next) {\r\n  // Do something with req/res\r\n  console.log(`${req.method} ${req.url}`);\r\n  \r\n  // Pass control to next middleware\r\n  next();\r\n}\r\n\r\n// Using middleware\r\nimport express from 'express';\r\nconst app = express();\r\n\r\napp.use(middleware);\r\n```\r\n\r\n## Types of Middleware\r\n\r\n### 1. Application-level Middleware\r\n\r\n```js\r\nconst app = express();\r\n\r\n// Runs for ALL requests\r\napp.use((req, res, next) => {\r\n  req.requestTime = Date.now();\r\n  next();\r\n});\r\n\r\n// Runs only for /api/* routes\r\napp.use('/api', (req, res, next) => {\r\n  console.log('API request');\r\n  next();\r\n});\r\n```\r\n\r\n### 2. Router-level Middleware\r\n\r\n```js\r\nconst router = express.Router();\r\n\r\n// Middleware for this router only\r\nrouter.use((req, res, next) => {\r\n  console.log('Router middleware');\r\n  next();\r\n});\r\n\r\nrouter.get('/users', (req, res) => {\r\n  res.json({ users: [] });\r\n});\r\n\r\napp.use('/api', router);\r\n```\r\n\r\n### 3. Error-handling Middleware\r\n\r\n```js\r\n// Must have 4 parameters\r\napp.use((err, req, res, next) => {\r\n  console.error(err.stack);\r\n  res.status(500).json({\r\n    error: 'Something went wrong!',\r\n    message: err.message\r\n  });\r\n});\r\n\r\n// Triggering error middleware\r\napp.get('/error', (req, res, next) => {\r\n  const error = new Error('Test error');\r\n  next(error); // Passes to error middleware\r\n});\r\n```\r\n\r\n### 4. Built-in Middleware\r\n\r\n```js\r\n// Parse JSON bodies\r\napp.use(express.json());\r\n\r\n// Parse URL-encoded bodies\r\napp.use(express.urlencoded({ extended: true }));\r\n\r\n// Serve static files\r\napp.use(express.static('public'));\r\n```\r\n\r\n## Common Middleware Examples\r\n\r\n### Authentication Middleware\r\n\r\n```js\r\nfunction authenticate(req, res, next) {\r\n  const token = req.headers.authorization?.split(' ')[1];\r\n  \r\n  if (!token) {\r\n    return res.status(401).json({ error: 'No token provided' });\r\n  }\r\n  \r\n  try {\r\n    const decoded = jwt.verify(token, process.env.JWT_SECRET);\r\n    req.user = decoded;\r\n    next();\r\n  } catch (err) {\r\n    res.status(401).json({ error: 'Invalid token' });\r\n  }\r\n}\r\n\r\n// Use on protected routes\r\napp.get('/profile', authenticate, (req, res) => {\r\n  res.json({ user: req.user });\r\n});\r\n```\r\n\r\n### Logging Middleware\r\n\r\n```js\r\nfunction logger(req, res, next) {\r\n  const start = Date.now();\r\n  \r\n  res.on('finish', () => {\r\n    const duration = Date.now() - start;\r\n    console.log(`${req.method} ${req.url} ${res.statusCode} - ${duration}ms`);\r\n  });\r\n  \r\n  next();\r\n}\r\n\r\napp.use(logger);\r\n```\r\n\r\n### Rate Limiting Middleware\r\n\r\n```js\r\nconst rateLimit = new Map();\r\n\r\nfunction rateLimiter(limit = 100, windowMs = 60000) {\r\n  return (req, res, next) => {\r\n    const ip = req.ip;\r\n    const now = Date.now();\r\n    \r\n    if (!rateLimit.has(ip)) {\r\n      rateLimit.set(ip, { count: 1, resetTime: now + windowMs });\r\n      return next();\r\n    }\r\n    \r\n    const record = rateLimit.get(ip);\r\n    \r\n    if (now > record.resetTime) {\r\n      // Window expired - reset and clean up\r\n      record.count = 1;\r\n      record.resetTime = now + windowMs;\r\n      return next();\r\n    }\r\n    \r\n    if (record.count >= limit) {\r\n      return res.status(429).json({ error: 'Too many requests' });\r\n    }\r\n    \r\n    record.count++;\r\n    next();\r\n  };\r\n}\r\n\r\n// Cleanup old entries periodically (prevents memory leak)\r\nsetInterval(() => {\r\n  const now = Date.now();\r\n  for (const [ip, record] of rateLimit.entries()) {\r\n    if (now > record.resetTime) {\r\n      rateLimit.delete(ip);\r\n    }\r\n  }\r\n}, 60000); // Clean up every minute\r\n  };\r\n}\r\n\r\napp.use(rateLimiter(100, 60000));\r\n```\r\n\r\n## Middleware Execution Order\r\n\r\n```js\r\napp.use((req, res, next) => {\r\n  console.log('1: First middleware');\r\n  next();\r\n});\r\n\r\napp.use((req, res, next) => {\r\n  console.log('2: Second middleware');\r\n  next();\r\n});\r\n\r\napp.get('/', (req, res) => {\r\n  console.log('3: Route handler');\r\n  res.send('Hello');\r\n});\r\n\r\n// Output:\r\n// 1: First middleware\r\n// 2: Second middleware\r\n// 3: Route handler\r\n```\r\n\r\n## Best Practices\r\n\r\n1. **Always call next()** unless sending a response\r\n2. **Order matters** - define middleware in correct sequence\r\n3. **Keep middleware focused** - single responsibility\r\n4. **Handle errors properly** - use error middleware\r\n5. **Use async/await** - wrap async middleware to catch errors\r\n\r\n```js\r\n// Async middleware wrapper\r\nconst asyncHandler = (fn) => (req, res, next) => {\r\n  Promise.resolve(fn(req, res, next)).catch(next);\r\n};\r\n\r\napp.get('/users', asyncHandler(async (req, res) => {\r\n  const users = await User.find();\r\n  res.json(users);\r\n}));\r\n```\r\n\r\n";

