const performanceOptimization = "Optimizing Node.js performance involves understanding the event loop, efficient resource usage, and applying best practices for handling I/O operations, memory, and CPU-intensive tasks.\r\n\r\n## 1. Avoid Blocking the Event Loop\r\n\r\n```js\r\n// ❌ Blocking - freezes the server\r\napp.get('/hash', (req, res) => {\r\n  const hash = crypto.pbkdf2Sync(password, salt, 100000, 64, 'sha512');\r\n  res.send(hash);\r\n});\r\n\r\n// ✅ Non-blocking - uses thread pool\r\napp.get('/hash', (req, res) => {\r\n  crypto.pbkdf2(password, salt, 100000, 64, 'sha512', (err, hash) => {\r\n    res.send(hash);\r\n  });\r\n});\r\n```\r\n\r\n## 2. Use Caching Effectively\r\n\r\n### In-Memory Caching\r\n\r\n```js\r\nimport NodeCache from 'node-cache';\r\nconst cache = new NodeCache({ stdTTL: 600 }); // 10 min TTL\r\n\r\nasync function getUserData(userId) {\r\n  // Check cache first\r\n  const cached = cache.get(`user:${userId}`);\r\n  if (cached) return cached;\r\n  \r\n  // Fetch from database\r\n  const user = await db.users.findById(userId);\r\n  \r\n  // Store in cache\r\n  cache.set(`user:${userId}`, user);\r\n  \r\n  return user;\r\n}\r\n```\r\n\r\n### Redis Caching\r\n\r\n```js\r\nimport Redis from 'ioredis';\r\nconst redis = new Redis();\r\n\r\nasync function getCachedData(key, fetchFn, ttl = 3600) {\r\n  const cached = await redis.get(key);\r\n  if (cached) return JSON.parse(cached);\r\n  \r\n  const data = await fetchFn();\r\n  await redis.setex(key, ttl, JSON.stringify(data));\r\n  \r\n  return data;\r\n}\r\n\r\n// Usage\r\nconst products = await getCachedData(\r\n  'products:all',\r\n  () => db.products.findAll(),\r\n  3600\r\n);\r\n```\r\n\r\n## 3. Database Query Optimization\r\n\r\n```js\r\n// ❌ N+1 Query Problem\r\nconst users = await User.findAll();\r\nfor (const user of users) {\r\n  user.posts = await Post.findAll({ where: { userId: user.id } });\r\n}\r\n\r\n// ✅ Eager loading - single query with JOIN\r\nconst users = await User.findAll({\r\n  include: [{ model: Post }]\r\n});\r\n\r\n// ✅ Use indexes\r\n// In your migration:\r\nawait queryInterface.addIndex('posts', ['userId']);\r\nawait queryInterface.addIndex('posts', ['createdAt']);\r\n\r\n// ✅ Select only needed fields\r\nconst users = await User.findAll({\r\n  attributes: ['id', 'name', 'email'] // Don't select everything\r\n});\r\n\r\n// ✅ Pagination\r\nconst users = await User.findAll({\r\n  limit: 20,\r\n  offset: (page - 1) * 20\r\n});\r\n```\r\n\r\n## 4. Use Streams for Large Data\r\n\r\n```js\r\n// ❌ Loads entire file in memory\r\napp.get('/download', async (req, res) => {\r\n  const data = await fs.promises.readFile('large-file.csv');\r\n  res.send(data);\r\n});\r\n\r\n// ✅ Stream the file\r\napp.get('/download', (req, res) => {\r\n  const stream = fs.createReadStream('large-file.csv');\r\n  res.setHeader('Content-Type', 'text/csv');\r\n  stream.pipe(res);\r\n});\r\n\r\n// ✅ Stream database results\r\napp.get('/export', async (req, res) => {\r\n  res.setHeader('Content-Type', 'application/json');\r\n  res.write('[');\r\n  \r\n  let first = true;\r\n  const cursor = User.find().cursor();\r\n  \r\n  for await (const user of cursor) {\r\n    if (!first) res.write(',');\r\n    res.write(JSON.stringify(user));\r\n    first = false;\r\n  }\r\n  \r\n  res.write(']');\r\n  res.end();\r\n});\r\n```\r\n\r\n## 5. Connection Pooling\r\n\r\n```js\r\n// PostgreSQL with pg\r\nimport { Pool } from 'pg';\r\n\r\nconst pool = new Pool({\r\n  max: 20, // Max connections in pool\r\n  idleTimeoutMillis: 30000,\r\n  connectionTimeoutMillis: 2000,\r\n});\r\n\r\n// Reuse connections from pool\r\napp.get('/users', async (req, res) => {\r\n  const client = await pool.connect();\r\n  try {\r\n    const result = await client.query('SELECT * FROM users');\r\n    res.json(result.rows);\r\n  } finally {\r\n    client.release(); // Return to pool\r\n  }\r\n});\r\n```\r\n\r\n## 6. Compression\r\n\r\n```js\r\nimport compression from 'compression';\r\n\r\n// Basic compression (uses sensible defaults)\r\napp.use(compression());\r\n\r\n// With custom options\r\napp.use(compression({\r\n  level: 6, // Compression level (1-9)\r\n  threshold: 1024, // Only compress if > 1KB\r\n}));\r\n\r\n// Custom filter to skip compression for certain requests\r\napp.use(compression({\r\n  filter: (req, res) => {\r\n    // Skip compression if client requests it\r\n    if (req.headers['x-no-compression']) return false;\r\n    \r\n    // Fallback to the default compression filter behavior\r\n    return compression.filter(req, res);\r\n  }\r\n}));\r\n```\r\n\r\n## 7. Use Clustering\r\n\r\n```js\r\nimport cluster from 'node:cluster';\r\nimport os from 'node:os';\r\n\r\nif (cluster.isPrimary) {\r\n  const numCPUs = os.cpus().length;\r\n  \r\n  for (let i = 0; i < numCPUs; i++) {\r\n    cluster.fork();\r\n  }\r\n  \r\n  cluster.on('exit', (worker) => {\r\n    console.log(`Worker ${worker.process.pid} died`);\r\n    cluster.fork(); // Restart\r\n  });\r\n} else {\r\n  await import('./app.js'); // Your Express app\r\n}\r\n\r\n// Or use PM2 (recommended)\r\n// pm2 start app.js -i max\r\n```\r\n\r\n## 8. Optimize JSON Operations\r\n\r\n```js\r\n// ❌ Slow for large objects\r\nconst data = JSON.parse(largeJsonString);\r\n\r\n// ✅ Use streaming JSON parser\r\nimport { parser } from 'stream-json';\r\nimport { streamArray } from 'stream-json/streamers/StreamArray.js';\r\n\r\nfs.createReadStream('large.json')\r\n  .pipe(parser())\r\n  .pipe(streamArray())\r\n  .on('data', ({ value }) => {\r\n    // Process each item\r\n  });\r\n\r\n// ✅ Use faster JSON libraries\r\nimport fastJson from 'fast-json-stringify';\r\n\r\nconst stringify = fastJson({\r\n  type: 'object',\r\n  properties: {\r\n    id: { type: 'integer' },\r\n    name: { type: 'string' }\r\n  }\r\n});\r\n\r\nconst json = stringify({ id: 1, name: 'John' }); // Faster than JSON.stringify\r\n```\r\n\r\n## 9. Monitoring and Profiling\r\n\r\n```js\r\n// Monitor event loop lag\r\nconst start = process.hrtime();\r\nsetImmediate(() => {\r\n  const delta = process.hrtime(start);\r\n  const lag = (delta[0] * 1e9 + delta[1]) / 1e6;\r\n  if (lag > 100) {\r\n    console.warn(`Event loop lag: ${lag}ms`);\r\n  }\r\n});\r\n\r\n// Memory monitoring\r\nsetInterval(() => {\r\n  const used = process.memoryUsage();\r\n  console.log({\r\n    heapUsed: `${Math.round(used.heapUsed / 1024 / 1024)}MB`,\r\n    heapTotal: `${Math.round(used.heapTotal / 1024 / 1024)}MB`\r\n  });\r\n}, 30000);\r\n```\r\n\r\n## Performance Checklist\r\n\r\n- ✅ Use async/await and don't block event loop\r\n- ✅ Implement caching (Redis, in-memory)\r\n- ✅ Optimize database queries (indexes, eager loading)\r\n- ✅ Use streams for large data\r\n- ✅ Enable compression\r\n- ✅ Use connection pooling\r\n- ✅ Cluster your application\r\n- ✅ Monitor performance metrics\r\n- ✅ Profile and identify bottlenecks\r\n\r\n";

