const securityBestPractices = "Security is critical for Node.js applications, especially those handling sensitive data or exposed to the internet. Here are the most common vulnerabilities and how to prevent them.\r\n\r\n## 1. SQL Injection Prevention\r\n\r\nNever concatenate user input directly into queries.\r\n\r\n```js\r\n// ❌ Vulnerable to SQL injection\r\nconst query = `SELECT * FROM users WHERE id = ${req.params.id}`;\r\ndb.query(query);\r\n\r\n// ✅ Use parameterized queries\r\nconst query = 'SELECT * FROM users WHERE id = ?';\r\ndb.query(query, [req.params.id]);\r\n\r\n// ✅ With an ORM (Sequelize)\r\nconst user = await User.findOne({\r\n  where: { id: req.params.id }\r\n});\r\n```\r\n\r\n## 2. NoSQL Injection Prevention\r\n\r\n```js\r\n// ❌ Vulnerable - user can pass { $gt: \"\" }\r\nconst user = await User.findOne({\r\n  username: req.body.username,\r\n  password: req.body.password\r\n});\r\n\r\n// ✅ Validate and sanitize input\r\nconst { username, password } = req.body;\r\n\r\nif (typeof username !== 'string' || typeof password !== 'string') {\r\n  return res.status(400).json({ error: 'Invalid input' });\r\n}\r\n\r\nconst user = await User.findOne({\r\n  username: username.toString(),\r\n  password: password.toString()\r\n});\r\n```\r\n\r\n## 3. XSS (Cross-Site Scripting) Prevention\r\n\r\n```js\r\n// ❌ Vulnerable - renders user input as HTML\r\napp.get('/profile', (req, res) => {\r\n  res.send(`<h1>Hello ${req.query.name}</h1>`);\r\n});\r\n\r\n// ✅ Escape HTML entities\r\nimport escapeHtml from 'escape-html';\r\n\r\napp.get('/profile', (req, res) => {\r\n  res.send(`<h1>Hello ${escapeHtml(req.query.name)}</h1>`);\r\n});\r\n\r\n// ✅ Use Content Security Policy\r\nimport helmet from 'helmet';\r\napp.use(helmet.contentSecurityPolicy({\r\n  directives: {\r\n    defaultSrc: [\"'self'\"],\r\n    scriptSrc: [\"'self'\"],\r\n  }\r\n}));\r\n```\r\n\r\n## 4. Using Helmet.js\r\n\r\nHelmet sets various HTTP headers to secure your app.\r\n\r\n```js\r\nimport helmet from 'helmet';\r\nimport express from 'express';\r\nconst app = express();\r\n\r\n// Use all default protections\r\napp.use(helmet());\r\n\r\n// Or configure individually\r\napp.use(helmet.xssFilter());\r\napp.use(helmet.noSniff());\r\napp.use(helmet.hidePoweredBy());\r\napp.use(helmet.frameguard({ action: 'deny' }));\r\n```\r\n\r\n## 5. Rate Limiting\r\n\r\nPrevent brute force and DDoS attacks.\r\n\r\n```js\r\nimport rateLimit from 'express-rate-limit';\r\n\r\nconst limiter = rateLimit({\r\n  windowMs: 15 * 60 * 1000, // 15 minutes\r\n  max: 100, // limit each IP to 100 requests per window\r\n  message: 'Too many requests, please try again later'\r\n});\r\n\r\napp.use('/api/', limiter);\r\n\r\n// Stricter limit for auth endpoints\r\nconst authLimiter = rateLimit({\r\n  windowMs: 60 * 60 * 1000, // 1 hour\r\n  max: 5,\r\n  message: 'Too many login attempts'\r\n});\r\n\r\napp.use('/api/login', authLimiter);\r\n```\r\n\r\n## 6. Secure Authentication\r\n\r\n```js\r\nimport bcrypt from 'bcrypt';\r\nimport jwt from 'jsonwebtoken';\r\n\r\n// Hash passwords\r\nconst hashPassword = async (password) => {\r\n  const salt = await bcrypt.genSalt(12);\r\n  return bcrypt.hash(password, salt);\r\n};\r\n\r\n// Verify passwords\r\nconst verifyPassword = async (password, hash) => {\r\n  return bcrypt.compare(password, hash);\r\n};\r\n\r\n// Generate JWT\r\nconst generateToken = (user) => {\r\n  return jwt.sign(\r\n    { id: user.id, email: user.email },\r\n    process.env.JWT_SECRET,\r\n    { expiresIn: '1h' }\r\n  );\r\n};\r\n\r\n// Use HTTP-only cookies for tokens\r\nres.cookie('token', token, {\r\n  httpOnly: true,\r\n  secure: process.env.NODE_ENV === 'production',\r\n  sameSite: 'strict',\r\n  maxAge: 3600000\r\n});\r\n```\r\n\r\n## 7. Input Validation\r\n\r\n```js\r\nimport Joi from 'joi';\r\n\r\nconst userSchema = Joi.object({\r\n  username: Joi.string().alphanum().min(3).max(30).required(),\r\n  email: Joi.string().email().required(),\r\n  password: Joi.string().min(8).pattern(/^(?=.*[A-Za-z])(?=.*\\d)/).required()\r\n});\r\n\r\napp.post('/register', async (req, res) => {\r\n  try {\r\n    const validated = await userSchema.validateAsync(req.body);\r\n    // Process validated data\r\n  } catch (err) {\r\n    res.status(400).json({ error: err.details[0].message });\r\n  }\r\n});\r\n```\r\n\r\n## 8. Secure Environment Variables\r\n\r\n```js\r\n// ❌ Never hardcode secrets\r\nconst JWT_SECRET = 'mysecret123';\r\n\r\n// ✅ Use environment variables\r\nimport 'dotenv/config';\r\nconst JWT_SECRET = process.env.JWT_SECRET;\r\n\r\n// ✅ Validate required env vars at startup\r\nconst requiredEnvVars = ['JWT_SECRET', 'DATABASE_URL', 'API_KEY'];\r\n\r\nrequiredEnvVars.forEach((varName) => {\r\n  if (!process.env[varName]) {\r\n    console.error(`Missing required env var: ${varName}`);\r\n    process.exit(1);\r\n  }\r\n});\r\n```\r\n\r\n## 9. HTTPS and Secure Cookies\r\n\r\n```js\r\n// Force HTTPS in production\r\nif (process.env.NODE_ENV === 'production') {\r\n  app.use((req, res, next) => {\r\n    if (req.header('x-forwarded-proto') !== 'https') {\r\n      return res.redirect(`https://${req.header('host')}${req.url}`);\r\n    }\r\n    next();\r\n  });\r\n}\r\n\r\n// Secure session configuration\r\nimport session from 'express-session';\r\n\r\napp.use(session({\r\n  secret: process.env.SESSION_SECRET,\r\n  resave: false,\r\n  saveUninitialized: false,\r\n  cookie: {\r\n    secure: true,\r\n    httpOnly: true,\r\n    sameSite: 'strict',\r\n    maxAge: 24 * 60 * 60 * 1000\r\n  }\r\n}));\r\n```\r\n\r\n## Security Checklist\r\n\r\n- ✅ Use parameterized queries (prevent SQL injection)\r\n- ✅ Validate and sanitize all user input\r\n- ✅ Use Helmet.js for security headers\r\n- ✅ Implement rate limiting\r\n- ✅ Hash passwords with bcrypt (salt rounds ≥ 12)\r\n- ✅ Use HTTPS in production\r\n- ✅ Store secrets in environment variables\r\n- ✅ Keep dependencies updated\r\n- ✅ Use HTTP-only, secure cookies\r\n- ✅ Implement proper CORS policies\r\n\r\n";

