const webServer = "To create a minimal `Hello, World!` HTTP server in Node.js, you can use the `http` module. It provides an HTTP server, and the createServer() method sets up a server instance with a callback function to handle incoming requests\r\n\r\n```js\r\nimport http from 'node:http';\r\n\r\nconst server = http.createServer((req, res) => {\r\n  res.writeHead(200, { 'Content-Type': 'text/plain' });\r\n  res.end('Hello World\\n');\r\n});\r\n\r\nserver.listen(3000, () => {\r\n  console.log('Server running at http://localhost:3000/');\r\n});\r\n```\r\n";

