const pureComponents = "Pure components re-render only when the props passed to the component changes. For example, if you have a pure child component inside a parent component state changes in the parent component will not re-render the child component unless the props passed to the child component change.\r\n\r\nTo create a pure component, you can use the `memo` function from React. It is a higher order component which takes a component as an argument and returns a new component. The new component renders only if the props change.\r\n\r\n```javascript\r\nimport React, { memo } from 'react';\r\n\r\nconst ChildComponent = ({ name }) => {\r\n  console.log('Rendering child component');\r\n  return <div>{name}</div>;\r\n};\r\n\r\nconst PureChildComponent = memo(ChildComponent);\r\n\r\nconst ParentComponent = () => {\r\n  const [count, setCount] = useState(0);\r\n  const [name, setName] = useState('John');\r\n\r\n  return (\r\n    <div>\r\n      <button onClick={() => setCount(count + 1)}>Count - {count}</button>\r\n      <button onClick={() => setName('Jane')}>Change name</button>\r\n      <PureChildComponent name={name} />\r\n    </div>\r\n  );\r\n};\r\n```";

