const suspense = "Suspense is a component in React that lets you specify the fallback content to display while waiting for a component to load. It is used in conjunction with `lazy()` to lazily load components.\r\n\r\n```js\r\nimport { lazy, Suspense } from 'react';\r\n\r\nconst LazyRoadmapRender = lazy(() => import('./RoadmapRender'));\r\n\r\nexport function App() {\r\n  const [show, setShow] = useState(false);\r\n  return (\r\n    <>\r\n      <button onClick={() => setShow(true)}>Show</button>\r\n      {show && (\r\n        <Suspense fallback={<div>Loading...</div>}>\r\n          <LazyRoadmapRender />\r\n        </Suspense>\r\n      )}\r\n    </>\r\n  );\r\n}\r\n```\r\n\r\nUntil the `RoadmapRender` component is loaded, the `Suspense` component will display the `Loading...` fallback content.\r\n";

